try {
  const wd = sim.worldData
  const NB = 16
  if (!wd.__tv || wd.__tv.v !== 3) {
    wd.__tv = { v: 3, ch: 1, sw: 0, held: 0, sHeld: 0, ct: 0, door: 0, laugh: 0, lseq: 0, lq: 0, lamp: 1, mug: -1,
      cast: [
        { x: -0.42, tx: -0.42, pose: 2, face: 1, talk: 0, row: 0.0, st: 'sit', t: 4, partner: -1, knocked: 0, rt: 0 },
        { x: 0.47, tx: 0.47, pose: 0, face: 1, talk: 0, row: 0.012, st: 'kitchen', t: 5, partner: -1, knocked: 0, rt: 0 },
        { x: 0.10, tx: 0.10, pose: 0, face: -1, talk: 0, row: -0.012, st: 'idle', t: 2, partner: -1, knocked: 0, rt: 0 },
        { x: 1.10, tx: 1.10, pose: 3, face: -1, talk: 0, row: 0.024, st: 'out', t: 7, partner: -1, knocked: 0, rt: 0 },
      ],
      pong: { bx: 0, by: 0, vx: 0.9, vy: 0.5, pa: 0, pb: 0, sa: 0, sb: 0 },
      boids: Array.from({ length: NB }, (_, i) => ({ x: Math.sin(i * 2.1) * 0.5, y: Math.cos(i * 1.7) * 0.5, vx: 0.2, vy: 0.1 })),
      tgt: { x: 0, y: 0, t: 0 } }
  }
  const G = wd.__tv
  const pdt = Math.min(dt, 0.05)

  // channel change: click anywhere or space
  const want = (wd.mouse_down && !G.held) || (wd.key_space && !G.sHeld)
  if (wd.mouse_down) G.held = 1; else G.held = 0
  if (wd.key_space) G.sHeld = 1; else G.sHeld = 0
  if (want) {
    G.ch = (G.ch + 1) % 6
    G.sw = 1
    wd.__play_sound = [
      { frequency: 1200, duration: 0.03, volume: 0.25, type: 'square' },
      { frequency: 90, duration: 0.15, volume: 0.2, type: 'sawtooth' },
    ]
  }
  G.sw = Math.max(0, G.sw - 2.2 * pdt)

  // ── ALGORITHM 1: Pong plays itself ──
  const P = G.pong
  P.bx += P.vx * pdt; P.by += P.vy * pdt
  if (P.by > 0.92 || P.by < -0.92) { P.vy = -P.vy; P.by = Math.sign(P.by) * 0.92 }
  const chase = (pad, ty) => pad + Math.max(-1.3 * pdt, Math.min(1.3 * pdt, ty - pad))
  P.pa = chase(P.pa, P.vx < 0 ? P.by : P.by * 0.3)
  P.pb = chase(P.pb, P.vx > 0 ? P.by : P.by * 0.3)
  if (P.bx < -0.82 && Math.abs(P.by - P.pa) < 0.19 && P.vx < 0) { P.vx = -P.vx * 1.04; P.vy += (P.by - P.pa) * 2.0; P.bx = -0.82 }
  if (P.bx > 0.82 && Math.abs(P.by - P.pb) < 0.19 && P.vx > 0) { P.vx = -P.vx * 1.04; P.vy += (P.by - P.pb) * 2.0; P.bx = 0.82 }
  if (Math.abs(P.bx) > 1.05) {
    if (P.bx > 0) P.sa = Math.min(5, P.sa + 1); else P.sb = Math.min(5, P.sb + 1)
    if (P.sa >= 5 || P.sb >= 5) { P.sa = 0; P.sb = 0 }
    P.bx = 0; P.by = 0; P.vx = Math.sign(-P.bx || (Math.random() < 0.5 ? 1 : -1)) * 0.9; P.vy = 0.5
    if (G.ch === 2) wd.__play_sound = { frequency: 220, duration: 0.12, volume: 0.25, type: 'square' }
  }
  const spd = Math.hypot(P.vx, P.vy)
  if (spd > 2.2) { P.vx *= 2.2 / spd; P.vy *= 2.2 / spd }

  // ── ALGORITHM 2: boids murmuration ──
  G.tgt.t -= pdt
  if (G.tgt.t <= 0) { G.tgt = { x: (Math.sin(Date.now ? 0 : 0) || Math.sin(G.sw * 7 + P.bx * 13)) * 0.6, y: Math.sin(P.by * 11 + G.ch * 3) * 0.5, t: 2.5 } }
  let cx = 0, cy = 0
  for (const b of G.boids) { cx += b.x; cy += b.y }
  cx /= NB; cy /= NB
  for (const b of G.boids) {
    // cohesion + target + separation + alignment-lite
    b.vx += ((cx - b.x) * 0.4 + (G.tgt.x - b.x) * 0.5) * pdt
    b.vy += ((cy - b.y) * 0.4 + (G.tgt.y - b.y) * 0.5) * pdt
    for (const o of G.boids) {
      if (o === b) continue
      const dx = b.x - o.x, dy = b.y - o.y
      const d2 = dx * dx + dy * dy
      if (d2 < 0.008 && d2 > 1e-6) { b.vx += dx / d2 * 0.0022 * pdt * 60; b.vy += dy / d2 * 0.0022 * pdt * 60 }
    }
    const sp = Math.hypot(b.vx, b.vy) || 1
    const want2 = 0.55
    b.vx *= 1 + (want2 - sp) / sp * 0.08
    b.vy *= 1 + (want2 - sp) / sp * 0.08
    b.x += b.vx * pdt; b.y += b.vy * pdt
    if (Math.abs(b.x) > 0.95) { b.vx -= Math.sign(b.x) * 1.5 * pdt }
    if (Math.abs(b.y) > 0.9) { b.vy -= Math.sign(b.y) * 1.5 * pdt }
  }

  // ── ALGORITHM 3: the sitcom — four lives moving through behavior zones ──
  G.ct += pdt
  G.laugh = Math.max(0, G.laugh - 1.1 * pdt)
  G.door = Math.max(0, G.door - 0.55 * pdt)
  if (G.lseq > 0) {
    G.lq -= pdt
    if (G.lq <= 0) {
      if (G.ch === 4) wd.__play_sound = { frequency: 280 + G.lseq * 55 + Math.random() * 40, duration: 0.07, volume: 0.22, type: 'square' }
      G.lq = 0.11; G.lseq--
    }
  }
  const SEATS = [-0.42, -0.20]
  const CAST = G.cast
  // everyone else notices: "!" bubbles + heads turn toward the thing
  const reactAll = (except, towardX) => {
    for (let k = 0; k < 4; k++) {
      const o = CAST[k]
      if (k === except || o.pose === 3) continue
      o.rt = 1.4
      if (o.st !== 'walk' && o.st !== 'chat') o.face = towardX > o.x ? 1 : -1
    }
  }
  for (let i = 0; i < 4; i++) {
    const c = CAST[i]
    c.t -= pdt
    c.rt = Math.max(0, (c.rt || 0) - pdt)
    if (c.st === 'walk') {
      const dw = c.tx - c.x
      c.face = dw > 0 ? 1 : -1
      c.x += Math.sign(dw) * Math.min(Math.abs(dw), 0.16 * pdt)
      c.pose = 1
      c.talk = 0
      if (Math.abs(dw) < 0.006) {
        c.st = c.next; c.t = 2.5 + Math.random() * 4
        if (c.st === 'sit') { c.pose = 2; c.face = c.x < -0.31 ? 1 : -1 }
        else if (c.st === 'out') { c.pose = 3; G.door = 1; c.t = 6 + Math.random() * 12 }
        else { c.pose = 0 }
        if (c.st === 'chat') c.t = 5 + Math.random() * 5
        if (c.st === 'window') c.face = -1
        if (c.st === 'kitchen') { c.face = 1; if (G.mug < 0) G.mug = i }
        if (c.st === 'lamp') {
          // the interaction: flip the switch — and everyone reacts
          G.lamp = 1 - G.lamp
          c.face = c.x < 0.13 ? 1 : -1
          c.t = 1.2 + Math.random() * 1.5
          if (G.ch === 4) wd.__play_sound = { frequency: G.lamp ? 900 : 480, duration: 0.05, volume: 0.3, type: 'square' }
          reactAll(i, 0.13)
          if (!G.lamp && Math.random() < 0.5) { G.laugh = 1; G.lseq = 5; G.lq = 0 }   // sometimes it IS the joke
        }
      }
      continue
    }
    if (c.st === 'chat') {
      const pr = CAST[c.partner]
      if (!pr || pr.st !== 'chat') { c.st = 'idle'; c.partner = -1; c.talk = 0; c.t = 2; continue }
      c.face = pr.x > c.x ? 1 : -1
      const tk = Math.floor(G.ct / 1.4) % 2
      c.talk = ((i < c.partner) ? tk === 0 : tk === 1) ? 1 : 0
      if (c.t <= 0 && i < c.partner) {
        // the punchline lands
        G.laugh = 1; G.lseq = 5; G.lq = 0
        pr.st = 'idle'; pr.talk = 0; pr.t = 2 + Math.random() * 3; pr.partner = -1
        c.st = 'idle'; c.talk = 0; c.t = 2 + Math.random() * 3; c.partner = -1
      }
      continue
    }
    if (c.st === 'out') {
      c.talk = 0
      if (c.t <= 0) {
        if (!c.knocked) {
          c.knocked = 1; c.t = 1.1
          if (G.ch === 4) wd.__play_sound = [{ frequency: 130, duration: 0.05, volume: 0.3, type: 'square' }, { frequency: 118, duration: 0.05, volume: 0.28, type: 'square' }]
          continue
        }
        c.knocked = 0; G.door = 1
        c.x = 0.84; c.st = 'walk'; c.pose = 1
        c.tx = -0.05 + Math.random() * 0.35; c.next = 'idle'
        reactAll(i, 0.86)
        if (G.ch === 4) wd.__play_sound = { frequency: 520, duration: 0.1, volume: 0.18, type: 'triangle' }
      }
      continue
    }
    // standing zones: when the timer runs out, pick the next scene beat
    c.talk = 0
    if (c.t <= 0) {
      if (G.mug === i) G.mug = -1              // mug goes back on the counter
      const r = Math.random()
      if (G.lamp === 0 && c.st !== 'lamp' && r < 0.6) {
        // somebody has to fix the lights
        c.st = 'walk'; c.tx = 0.075; c.next = 'lamp'
      } else if (G.lamp === 1 && i === 2 && r < 0.12) {
        // the prankster reaches for the switch
        c.st = 'walk'; c.tx = 0.075; c.next = 'lamp'
      } else if (r < 0.30) {
        let j = -1
        for (let k = 0; k < 4; k++) {
          const o = CAST[k]
          if (k !== i && o.partner < 0 && o.pose !== 3 && o.st !== 'walk' && o.st !== 'chat' && o.st !== 'out') { j = k; break }
        }
        if (j >= 0) {
          const o = CAST[j]
          const mx2 = Math.max(-0.55, Math.min(0.6, (c.x + o.x) / 2))
          c.partner = j; o.partner = i
          c.st = 'walk'; c.tx = mx2 - 0.055; c.next = 'chat'
          o.st = 'walk'; o.tx = mx2 + 0.055; o.next = 'chat'
          if (o.pose === 2) o.pose = 1
        } else { c.t = 2 }
      }
      else if (r < 0.50) { c.st = 'walk'; c.tx = SEATS[i % 2] + (Math.random() - 0.5) * 0.03; c.next = 'sit' }
      else if (r < 0.66) { c.st = 'walk'; c.tx = 0.44; c.next = 'kitchen' }
      else if (r < 0.80) { c.st = 'walk'; c.tx = -0.62; c.next = 'window' }
      else if (r < 0.88 && i === 3) { c.st = 'walk'; c.tx = 0.82; c.next = 'out' }
      else { c.st = 'walk'; c.tx = -0.15 + Math.random() * 0.45; c.next = 'idle' }
    }
  }

  // ── ALGORITHM 4: the VILLAGE — utility AI over behavior zones ──
  if (!G.vg) G.vg = { clock: 0.05, rain: 0, rainT: 40 + Math.random() * 60,
    dog: { x: 0.3, y: 0.5, tx: 0.3, ty: 0.5 },
    folk: Array.from({ length: 8 }, (_, i) => ({
      x: -0.6 + i * 0.17, y: 0.42, tx: -0.6 + i * 0.17, ty: 0.42,
      energy: 0.5 + Math.random() * 0.4, hunger: Math.random() * 0.5, social: Math.random() * 0.6,
      home: i % 3, act: 0, dir: 1, t: Math.random() * 3 })) }
  const V = G.vg
  {
    const Z = { hut: [[-0.62, 0.02], [-0.30, -0.06], [0.02, 0.0]], well: [0.32, 0.36],
                field: [-0.45, 0.52], market: [0.58, 0.18], tavern: [0.62, 0.52] }
    V.clock = (V.clock + pdt / 60) % 1                     // one minute per day
    const day = Math.max(0, Math.min(1, Math.cos(V.clock * Math.PI * 2 - Math.PI / 2) * 1.6 + 0.4))
    V.rainT -= pdt
    if (V.rainT <= 0) { V.rainT = V.rain > 0.5 ? 40 + Math.random() * 80 : 8 + Math.random() * 6; V.rain = V.rain > 0.5 ? 0 : 1 }
    const rainNow = V.rain > 0.5
    // dawn well queue membership, resolved each frame
    let queueN = 0
    for (const f of V.folk) {
      f.energy = Math.max(0, f.energy - pdt * 0.006)
      f.hunger = Math.min(1, f.hunger + pdt * 0.008)
      f.social = Math.max(0, f.social - pdt * 0.005)
      const night = V.clock > 0.68 || V.clock < 0.02
      const dawn = V.clock >= 0.02 && V.clock < 0.14
      const evening = V.clock >= 0.52 && V.clock <= 0.68
      f.t -= pdt
      const arrive = Math.hypot(f.tx - f.x, f.ty - f.y) < 0.015
      if (!arrive) {
        // walking toward the chosen zone
        const d2 = Math.hypot(f.tx - f.x, f.ty - f.y)
        f.dir = f.tx > f.x ? 1 : -1
        f.x += (f.tx - f.x) / d2 * Math.min(d2, 0.11 * pdt)
        f.y += (f.ty - f.y) / d2 * Math.min(d2, 0.11 * pdt)
        f.act = 1
        continue
      }
      // at the zone: do the thing the zone is for
      if (f.act === 2) f.energy = Math.min(1, f.energy + pdt * 0.05)
      if (f.act === 3) { /* work */ }
      if (f.act === 5) { f.social = Math.min(1, f.social + pdt * 0.05); f.hunger = Math.max(0, f.hunger - pdt * 0.02) }
      if (f.act === 4) f.hunger = Math.max(0, f.hunger - pdt * 0.05)
      if (f.t > 0) continue
      f.t = 2 + Math.random() * 3
      // utility choice, gated by the clock and the sky
      if (rainNow && !night) {
        const hh = Z.hut[f.home]
        f.tx = hh[0] + 0.02; f.ty = hh[1] + 0.10; f.act = 0
        if (Math.hypot(f.tx - f.x, f.ty - f.y) < 0.02) f.act = 0
      } else if (night || f.energy < 0.12) {
        const hh = Z.hut[f.home]
        f.tx = hh[0]; f.ty = hh[1] + 0.06; f.act = 2
      } else if (dawn) {
        // the well queue: each joiner takes the next place in line
        f.tx = Z.well[0] - 0.05 - queueN * 0.045; f.ty = Z.well[1] + 0.02; f.act = 0; queueN++
      } else if (f.hunger > 0.72) {
        f.tx = Z.market[0] + (Math.random() - 0.5) * 0.05; f.ty = Z.market[1] + 0.05; f.act = 4
      } else if (evening || f.social < 0.18) {
        f.tx = Z.tavern[0] + (Math.random() - 0.5) * 0.10; f.ty = Z.tavern[1] + 0.08; f.act = 5
      } else {
        f.tx = Z.field[0] + (Math.random() - 0.5) * 0.36; f.ty = Z.field[1] + (Math.random() - 0.5) * 0.18; f.act = 3
      }
    }
    // the dog follows whoever is walking; otherwise naps by the tavern
    let best = null, bd = 9
    for (const f of V.folk) { if (f.act === 1) { const dd2 = Math.hypot(f.x - V.dog.x, f.y - V.dog.y); if (dd2 < bd) { bd = dd2; best = f } } }
    const dtx = best ? best.x - 0.04 * (best.dir || 1) : Z.tavern[0] - 0.12
    const dty = best ? best.y + 0.01 : Z.tavern[1] + 0.09
    const ddd = Math.hypot(dtx - V.dog.x, dty - V.dog.y)
    if (ddd > 0.02) { V.dog.x += (dtx - V.dog.x) / ddd * Math.min(ddd, 0.14 * pdt); V.dog.y += (dty - V.dog.y) / ddd * Math.min(ddd, 0.14 * pdt) }
  }

  // publish: the whiteboard is multiplexed by channel — only the active
  // channel's world rides the wire (the sims all keep living in here)
  let u
  if (G.ch === 5) {
    u = [G.ch, G.sw, 0, V.clock, V.rain, V.dog.x, V.dog.y, 0, 0, 0]
    for (const f of V.folk) u.push(f.x, f.y, f.act, f.dir)
    u.push(0)
  } else {
    u = [G.ch, G.sw, G.door, P.bx, P.by, P.pa, P.pb, P.sa, P.sb, G.lamp + (G.mug >= 0 ? 2 : 0)]
  for (const b of G.boids) u.push(b.x, b.y)
  for (let i = 0; i < 4; i++) {
    const c = G.cast[i]
    let mode = c.talk
    if (c.rt > 0) mode = 2
    else if (G.mug === i && c.st === 'kitchen') mode = 3
    u.push(c.x, c.pose, c.face, mode, c.row)
  }
  u.push(G.laugh)
  }
  wd.gpuUniforms = u
  wd.hud = [
    { id: 'tv_ch', type: 'text', x: '14px', y: '12px', text: 'CH ' + (G.ch + 1) + '  \u00b7  ' + ['STATIC', 'PLASMA', 'PONG', 'BOIDS', 'SITCOM', 'VILLAGE'][G.ch], color: '#c9b370', fontSize: '13px' },
    { id: 'tv_hint', type: 'text', x: '14px', bottom: '12px', text: 'click / space: change channel', color: '#6f8f8a', fontSize: '12px' },
  ]
} catch (e) { /* keep the sim alive */ }

