// ── the channel words: each is a callable shader — signature (q: -1..1 screen, t) ──

fn ch_static(q: vec2f, t: f32) -> vec3f {
  let n = hash21(floor(q * vec2f(160.0, 120.0)) + floor(t * 60.0) * 7.3);
  var v = 0.25 + 0.75 * n;
  // rolling tear bar
  let bar = fract(q.y * 0.5 - t * 0.35);
  if (bar < 0.06) { v *= 0.45; }
  return vec3f(v);
}

fn ch_plasma(q: vec2f, t: f32) -> vec3f {
  var v = sin(q.x * 6.0 + t * 1.2);
  v += sin((q.y * 5.0 + t) * 0.8);
  v += sin((q.x + q.y) * 4.0 + t * 0.7);
  v += sin(length(q * 5.0) - t * 1.5);
  v *= 0.25;
  return vec3f(0.5 + 0.5 * sin(6.2831 * v), 0.5 + 0.5 * sin(6.2831 * v + 2.1), 0.5 + 0.5 * sin(6.2831 * v + 4.2));
}

fn ch_pong(q: vec2f, t: f32) -> vec3f {
  var col = vec3f(0.02, 0.03, 0.02);
  // net
  if (abs(q.x) < 0.012 && fract(q.y * 5.0) < 0.55) { col = vec3f(0.35); }
  // paddles (hook-simulated)
  if (abs(q.x + 0.85) < 0.03 && abs(q.y - uni(5)) < 0.16) { col = vec3f(1.4); }
  if (abs(q.x - 0.85) < 0.03 && abs(q.y - uni(6)) < 0.16) { col = vec3f(1.4); }
  // ball
  if (abs(q.x - uni(3)) < 0.035 && abs(q.y - uni(4)) < 0.045) { col = vec3f(1.8); }
  // score pips
  for (var i = 0; i < 5; i++) {
    if (f32(i) < uni(7) && length(q - vec2f(-0.5 + f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
    if (f32(i) < uni(8) && length(q - vec2f(0.5 - f32(i) * 0.08, -0.85)) < 0.022) { col = vec3f(1.0); }
  }
  return col;
}

fn ch_boids(q: vec2f, t: f32) -> vec3f {
  var col = mix(vec3f(0.03, 0.05, 0.10), vec3f(0.10, 0.14, 0.22), q.y * -0.5 + 0.5);
  // moon
  col += vec3f(0.5, 0.5, 0.42) * exp(-length(q - vec2f(0.55, -0.55)) * 9.0);
  // the flock (hook-simulated)
  for (var i = 0; i < 16; i++) {
    let b = vec2f(uni(10 + i * 2), uni(11 + i * 2));
    let d = length(q - b);
    if (d < 0.028) { col = vec3f(0.02); }                    // bird body
    col += vec3f(0.05, 0.05, 0.04) * exp(-d * 40.0);         // faint presence
  }
  return col;
}


fn sc_box(p: vec2f, c: vec2f, b: vec2f, r: f32) -> f32 {
  let d = abs(p - c) - b;
  return length(max(d, vec2f(0.0))) + min(max(d.x, d.y), 0.0) - r;
}

// CH 5 — SITCOM. The hook runs four little lives through behavior zones
// (couch, kitchen, window, door, center-stage); the tube just draws them.
fn ch_sitcom(q: vec2f, t: f32) -> vec3f {
  let FLOOR = 0.42;
  // the set: warm wall, wood floor
  var col = mix(vec3f(0.20, 0.14, 0.11), vec3f(0.13, 0.09, 0.08), q.y * 0.5 + 0.5);
  col *= 0.94 + 0.06 * sin(q.x * 40.0);
  if (q.y > FLOOR) {
    col = mix(vec3f(0.17, 0.11, 0.06), vec3f(0.10, 0.06, 0.04), (q.y - FLOOR) * 1.6);
    col *= 0.9 + 0.1 * sin(q.x * 24.0 + q.y * 60.0);
  }
  // window on the night
  let wd2 = sc_box(q, vec2f(-0.72, -0.28), vec2f(0.13, 0.17), 0.02);
  if (wd2 < 0.0) {
    col = vec3f(0.02, 0.03, 0.07);
    if (hash21(floor(q * 30.0)) > 0.992) { col += vec3f(0.6); }
    col += vec3f(0.35, 0.35, 0.30) * exp(-length(q - vec2f(-0.68, -0.38)) * 14.0);
    if (abs(q.x + 0.72) < 0.012 || abs(q.y + 0.28) < 0.012) { col = vec3f(0.24, 0.17, 0.12); }
  } else if (wd2 < 0.02) { col = vec3f(0.26, 0.19, 0.13); }
  // the door — uni(2) swings it open on a dark hallway
  let dOpen = uni(2);
  let dframe = sc_box(q, vec2f(0.86, 0.12), vec2f(0.11, 0.30), 0.01);
  if (dframe < 0.0) {
    col = vec3f(0.03, 0.025, 0.032);
    if (q.x > 0.75 + dOpen * 0.17) {
      col = vec3f(0.23, 0.15, 0.09) * (0.85 + 0.15 * sin(q.y * 30.0));
      if (length(q - vec2f(0.78 + dOpen * 0.17, 0.14)) < 0.012) { col = vec3f(0.55, 0.45, 0.25); }
    }
  } else if (dframe < 0.018) { col = vec3f(0.28, 0.20, 0.13); }
  // couch
  let cc = vec2f(-0.30, 0.32);
  if (sc_box(q, cc + vec2f(0.0, -0.10), vec2f(0.27, 0.09), 0.04) < 0.0) { col = vec3f(0.36, 0.11, 0.11); }
  if (sc_box(q, cc + vec2f(0.0, 0.05), vec2f(0.27, 0.06), 0.04) < 0.0) {
    col = vec3f(0.45, 0.14, 0.13);
    if (abs(q.x - cc.x) < 0.004) { col *= 0.8; }
  }
  if (sc_box(q, cc + vec2f(-0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0 ||
      sc_box(q, cc + vec2f(0.30, 0.0), vec2f(0.035, 0.12), 0.03) < 0.0) { col = vec3f(0.42, 0.13, 0.12); }
  // kitchen counter + mug
  if (sc_box(q, vec2f(0.52, 0.47), vec2f(0.14, 0.08), 0.01) < 0.0) { col = vec3f(0.20, 0.16, 0.12); }
  if (sc_box(q, vec2f(0.52, 0.385), vec2f(0.155, 0.014), 0.005) < 0.0) { col = vec3f(0.55, 0.50, 0.42); }
  if ((i32(uni(9) + 0.5) & 2) == 0 && sc_box(q, vec2f(0.47, 0.355), vec2f(0.012, 0.014), 0.004) < 0.0) { col = vec3f(0.75, 0.68, 0.60); }
  // lamp — a real object: someone can turn it off (uni 9 bit 0)
  let props = i32(uni(9) + 0.5);
  let lampOn = f32(props & 1);
  if (abs(q.x - 0.13) < 0.006 && q.y > -0.02 && q.y < FLOOR) { col = vec3f(0.1, 0.1, 0.1); }
  if (q.y > -0.11 && q.y < -0.02 && abs(q.x - 0.13) < 0.035 + (q.y + 0.11) * 0.45) {
    col = mix(vec3f(0.16, 0.14, 0.13), vec3f(0.85, 0.65, 0.35), lampOn);
  }
  col += vec3f(0.5, 0.35, 0.15) * exp(-length((q - vec2f(0.13, 0.05)) * vec2f(1.0, 0.8)) * 3.2) * 0.35 * lampOn;

  // ── the cast (uni 42..61: x, pose, face, talk, row per character) ──
  for (var i = 0; i < 4; i++) {
    let ux = uni(42 + i * 5);
    let pose = uni(43 + i * 5);
    if (pose > 2.5) { continue; }
    let face = uni(44 + i * 5);
    let talk = uni(45 + i * 5);
    let row = uni(46 + i * 5);
    let fi = f32(i);
    var shirt = vec3f(0.75, 0.55, 0.15);
    var hair = vec3f(0.12, 0.09, 0.05);
    if (i == 1) { shirt = vec3f(0.15, 0.50, 0.50); hair = vec3f(0.35, 0.20, 0.08); }
    if (i == 2) { shirt = vec3f(0.55, 0.22, 0.10); hair = vec3f(0.08, 0.08, 0.08); }
    if (i == 3) { shirt = vec3f(0.35, 0.18, 0.42); hair = vec3f(0.50, 0.45, 0.40); }
    let hgt = 0.30 + fi * 0.014;
    let sitting = pose > 1.5;
    let walking = abs(pose - 1.0) < 0.25;
    let bob = select(0.0, abs(sin(t * 7.0 + fi * 2.0)) * 0.012, walking);
    let feetY = select(FLOOR + row, 0.415, sitting) - bob;
    let hipY = select(feetY - hgt * 0.42, 0.285, sitting);   // cushion top, not inside it
    let torsoC = vec2f(ux, hipY - hgt * 0.19);
    let headC = vec2f(ux + face * 0.008, hipY - hgt * 0.36);
    if (sitting) {
      // thigh out along the seat, shin down to the floor
      let kneeX = ux + face * 0.055;
      if (sc_box(q, vec2f((ux + kneeX) * 0.5, hipY + 0.012), vec2f(abs(kneeX - ux) * 0.5 + 0.008, 0.014), 0.008) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
      if (sc_box(q, vec2f(kneeX, (hipY + 0.012 + feetY) * 0.5), vec2f(0.011, (feetY - hipY - 0.012) * 0.5), 0.006) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    } else {
      let sw = select(0.0, sin(t * 9.0 + fi * 2.0) * 0.016, walking);
      if (sc_box(q, vec2f(ux - 0.014 + sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0 ||
          sc_box(q, vec2f(ux + 0.014 - sw, (hipY + feetY) * 0.5), vec2f(0.010, (feetY - hipY) * 0.5), 0.006) < 0.0) { col = vec3f(0.14, 0.13, 0.18); }
    }
    if (sc_box(q, torsoC, vec2f(0.036, hgt * 0.20), 0.02) < 0.0) { col = shirt; }
    let hd = length(q - headC);
    if (hd < 0.036) { col = vec3f(0.85, 0.62, 0.45); }
    if (hd < 0.038 && q.y < headC.y - 0.010) { col = hair; }
    if (fract(t * 0.31 + fi * 0.37) > 0.06) {
      if (length(q - (headC + vec2f(face * 0.012 - 0.008, 0.004))) < 0.0035 ||
          length(q - (headC + vec2f(face * 0.012 + 0.008, 0.004))) < 0.0035) { col = vec3f(0.05, 0.05, 0.05); }
    }
    if (talk > 0.5 && talk < 1.5) {
      let bc = headC + vec2f(face * 0.11, -0.105);
      let bd = sc_box(q, bc, vec2f(0.065, 0.030), 0.02);
      if (bd < 0.0) {
        col = vec3f(0.92, 0.92, 0.90);
        for (var k = 0; k < 3; k++) {
          if (fract(t * 0.9 + fi * 0.5) > f32(k) * 0.3 &&
              length(q - (bc + vec2f(-0.03 + f32(k) * 0.03, 0.0))) < 0.008) { col = vec3f(0.25, 0.25, 0.25); }
        }
      } else if (bd < 0.006 && bd >= 0.0) { col = vec3f(0.6, 0.6, 0.58); }
    } else if (talk > 1.5 && talk < 2.5) {
      // "!" — something just happened
      let bc = headC + vec2f(face * 0.05, -0.095);
      let bd = sc_box(q, bc, vec2f(0.026, 0.028), 0.016);
      if (bd < 0.0) {
        col = vec3f(0.95, 0.90, 0.70);
        if (abs(q.x - bc.x) < 0.005 && q.y > bc.y - 0.018 && q.y < bc.y + 0.006) { col = vec3f(0.55, 0.15, 0.10); }
        if (length(q - (bc + vec2f(0.0, 0.016))) < 0.005) { col = vec3f(0.55, 0.15, 0.10); }
      } else if (bd < 0.005 && bd >= 0.0) { col = vec3f(0.65, 0.55, 0.40); }
    } else if (talk > 2.5) {
      // the mug, in hand — raised for a sip now and then, steam curling
      let sip = smoothstep(0.55, 0.9, sin(t * 1.1 + fi * 2.0)) * 0.035;
      let mc = vec2f(ux + face * 0.052, hipY - hgt * 0.16 - sip);
      if (sc_box(q, mc, vec2f(0.013, 0.015), 0.004) < 0.0) { col = vec3f(0.75, 0.68, 0.60); }
      let sx = mc.x + sin((mc.y - q.y) * 30.0 + t * 2.0) * 0.008;
      if (q.y < mc.y - 0.02 && q.y > mc.y - 0.07 && abs(q.x - sx) < 0.004) {
        col = mix(col, vec3f(0.7, 0.7, 0.72), 0.35 * (1.0 - (mc.y - q.y) * 14.0));
      }
    }
  }
  // lights out: the room falls into blue moonlight until someone fixes it
  col *= mix(vec3f(0.34, 0.38, 0.55), vec3f(1.0, 1.0, 1.0), lampOn);
  // the laugh: warm audience light washing up from below
  col += vec3f(0.45, 0.32, 0.12) * uni(62) * (0.6 + 0.4 * sin(t * 18.0)) * (0.3 + 0.7 * smoothstep(0.0, 0.8, q.y));
  return col;
}


// CH 6 — VILLAGE: behavior zones under real light. The hook runs the society;
// this renders it like a painting: sun-angle cast shadows, normal-mapped
// ground, window light pools at night, wet-sky reflections in rain.
fn vg_box(p: vec2f, c: vec2f, b: vec2f) -> f32 {
  let d = abs(p - c) - b;
  return length(max(d, vec2f(0.0))) + min(max(d.x, d.y), 0.0);
}
fn vg_seg(p: vec2f, a: vec2f, b: vec2f) -> f32 {
  let pa = p - a;
  let ba = b - a;
  let h = clamp(dot(pa, ba) / max(dot(ba, ba), 1e-6), 0.0, 1.0);
  return length(pa - ba * h);
}

fn ch_village(q: vec2f, t: f32) -> vec3f {
  let clock = uni(3);
  let rain = uni(4);
  let sunA = clock * 6.2831853;
  let sunEl = max(sin(sunA + 1.5707963), 0.0);        // 1 at noon, 0 at night
  let day = clamp(sunEl * 1.5, 0.0, 1.0);
  let duskW = exp(-pow((sunEl - 0.12) * 7.0, 2.0));   // golden hour
  let night = 1.0 - day;
  // screen-space sun: travels east→west; light direction + shadow stretch
  let sunP = vec2f(-cos(sunA), -0.45 - sunEl * 0.4);
  let sdir = normalize(vec2f(sunP.x - 0.0, 0.35));    // shadows fall away from the sun
  let shLen = clamp(0.35 / max(sunEl, 0.12), 0.35, 1.8);

  // key + fill by the hour
  var sunCol = mix(vec3f(1.25, 0.62, 0.30), vec3f(1.18, 1.08, 0.92), clamp(sunEl * 2.2, 0.0, 1.0));
  sunCol = mix(sunCol, sunCol * vec3f(0.5, 0.55, 0.7), rain * 0.65);
  let ambCol = mix(vec3f(0.10, 0.13, 0.24), mix(vec3f(0.34, 0.40, 0.55), vec3f(0.45, 0.42, 0.50), duskW), day)
             * mix(1.0, 0.6, rain * 0.5);

  // ── sky ──
  var sky = mix(vec3f(0.015, 0.02, 0.06), mix(vec3f(0.35, 0.52, 0.74), vec3f(0.62, 0.42, 0.38), duskW), day);
  sky = mix(sky, sky * vec3f(0.45, 0.48, 0.58), rain * 0.75);
  sky += sunCol * exp(-length(q - sunP) * 2.2) * 0.25 * day;               // haze around the sun
  var col = sky;
  col += sunCol * 2.2 * exp(-dot(q - sunP, q - sunP) * 220.0) * step(0.02, sunEl) * (1.0 - rain * 0.7);
  let moonP = vec2f(cos(sunA), -0.45 - max(-sin(sunA + 1.5707963), 0.0) * 0.4);
  col += vec3f(0.75, 0.8, 0.95) * exp(-dot(q - moonP, q - moonP) * 500.0) * night * 1.2;
  if (night > 0.5) {
    let sp = q * 26.0;
    if (hash21(floor(sp)) > 0.985 && q.y < -0.2) {
      col += vec3f(0.7) * smoothstep(0.18, 0.04, length(fract(sp) - 0.5)) * (night - 0.5) * (1.0 - rain);
    }
  }
  // drifting clouds
  let cl = fbm(q * vec2f(1.6, 3.2) + vec2f(t * 0.02, 0.0), 3);
  if (q.y < -0.15) { col = mix(col, mix(sky * 1.25, vec3f(0.5, 0.5, 0.55), rain * 0.6), smoothstep(0.55, 0.8, cl) * 0.7); }

  let HOR = -0.16;
  if (q.y > HOR) {
    // ── the ground, lit for real ──
    // albedo: grass with wind, dirt paths worn between the zones, tilled field
    var alb = mix(vec3f(0.09, 0.17, 0.06), vec3f(0.15, 0.26, 0.09),
                  fbm(q * 6.0 + vec2f(sin(t * 0.7 + q.y * 4.0) * 0.03, 0.0), 3));
    var rough = 0.9;
    // paths: hut row → well → market → tavern → field
    var pd = vg_seg(q, vec2f(-0.6, 0.08), vec2f(0.32, 0.34));
    pd = min(pd, vg_seg(q, vec2f(0.32, 0.34), vec2f(0.6, 0.5)));
    pd = min(pd, vg_seg(q, vec2f(0.32, 0.34), vec2f(0.58, 0.16)));
    pd = min(pd, vg_seg(q, vec2f(-0.3, 0.0), vec2f(-0.45, 0.5)));
    let path = smoothstep(0.045, 0.015, pd + (fbm(q * 14.0, 2) - 0.5) * 0.02);
    alb = mix(alb, vec3f(0.24, 0.18, 0.12), path * 0.85);
    if (path > 0.3) { rough = 0.55; }
    // the field
    let fb = vg_box(q, vec2f(-0.45, 0.54), vec2f(0.25, 0.15));
    if (fb < 0.0) {
      let rows = 0.5 + 0.5 * sin((q.y + q.x * 0.15) * 80.0);
      alb = mix(vec3f(0.15, 0.10, 0.06), vec3f(0.24, 0.17, 0.10), rows);
      alb = mix(alb, vec3f(0.2, 0.28, 0.1), smoothstep(0.3, 0.7, fbm(q * 9.0, 2)) * 0.4);
      rough = 0.7;
    }
    // ground normal from albedo bumps
    let e = 0.012;
    let hC = fbm(q * 6.0, 3);
    let nx = fbm(q * 6.0 + vec2f(e, 0.0), 3) - hC;
    let ny = fbm(q * 6.0 + vec2f(0.0, e), 3) - hC;
    let n3 = normalize(vec3f(-nx * 3.0, -ny * 3.0, 1.0));
    let l3 = normalize(vec3f(-sdir.x, -sdir.y, 0.5 + sunEl));
    var lit = ambCol + sunCol * max(dot(n3, l3), 0.0) * day * 1.15;
    // wet ground: the sky lies in the puddles
    let wet = rain * (0.35 + 0.65 * path) * smoothstep(0.4, 0.7, fbm(q * 8.0 + 3.0, 2));
    var g = alb * lit;
    g = mix(g, sky * 0.9 + sunCol * exp(-length(q - sunP) * 3.0) * 0.3, wet * 0.65);
    col = g;
  }

  // ── cast shadows first: every standing thing owns a piece of the dark ──
  let shade = 1.0 - (0.55 * day + 0.15);
  var shadowK = 1.0;
  {
    // hut + tavern + well shadows: skewed quads along sdir
    for (var hI = 0; hI < 5; hI++) {
      var hc = vec2f(0.0);
      var hw = 0.10;
      if (hI == 0) { hc = vec2f(-0.62, 0.04); }
      if (hI == 1) { hc = vec2f(-0.30, -0.04); }
      if (hI == 2) { hc = vec2f(0.02, 0.02); }
      if (hI == 3) { hc = vec2f(0.62, 0.47); hw = 0.14; }
      if (hI == 4) { hc = vec2f(0.32, 0.35); hw = 0.05; }
      let base = hc + vec2f(0.0, 0.055);
      let rel = q - base;
      let along = dot(rel, sdir);
      let across = rel.x * sdir.y - rel.y * sdir.x;
      if (along > 0.0 && along < shLen * hw * 2.2 && abs(across) < hw * (1.0 - along / (shLen * hw * 2.4))) {
        shadowK = min(shadowK, 1.0 - 0.5 * day * (1.0 - along / (shLen * hw * 2.2)));
      }
    }
  }
  if (q.y > HOR) { col *= shadowK; }

  // ── structures, sun-side lit ──
  let sunSide = sign(-sdir.x);
  for (var hI = 0; hI < 4; hI++) {
    var hc = vec2f(0.0);
    var s = 1.0;
    var warmW = clamp(0.9 - day, 0.0, 1.0);
    if (hI == 0) { hc = vec2f(-0.62, 0.0); }
    if (hI == 1) { hc = vec2f(-0.30, -0.08); }
    if (hI == 2) { hc = vec2f(0.02, -0.02); }
    if (hI == 3) { hc = vec2f(0.62, 0.42); s = 1.5; warmW = clamp(warmW + 0.35, 0.0, 1.0); }
    // wall
    let wb = vg_box(q, hc + vec2f(0.0, 0.032 * s), vec2f(0.082, 0.05) * s);
    if (wb < 0.0) {
      var wall = mix(vec3f(0.32, 0.26, 0.18), vec3f(0.42, 0.35, 0.24), fbm((q - hc) * 30.0, 2));  // daub + timber
      if (abs(fract((q.x - hc.x) * 26.0) - 0.5) < 0.06 || abs(q.y - hc.y - 0.01) < 0.004) { wall *= 0.62; }  // beams
      let faceLit = 0.5 + 0.5 * sunSide * sign(q.x - hc.x);
      col = wall * (ambCol + sunCol * day * (0.35 + 0.75 * faceLit));
      col *= 0.75 + 0.25 * smoothstep(0.0, 0.02 * s, (hc.y + 0.082 * s) - q.y);   // AO at the base
    }
    // thatch roof
    let rq = q - (hc - vec2f(0.0, 0.05 * s));
    let roofHalf = (0.105 * s) * (1.0 - clamp(-rq.y / (0.07 * s), 0.0, 1.0));
    if (abs(rq.x) < roofHalf && rq.y < 0.004 && rq.y > -0.075 * s) {
      var th = mix(vec3f(0.35, 0.26, 0.12), vec3f(0.5, 0.4, 0.2), fract((rq.x * 60.0) + fbm(rq * 40.0, 2)));
      th *= 0.8 + 0.2 * sin(rq.y * 200.0);
      let roofLit = 0.45 + 0.55 * clamp(dot(normalize(vec2f(sign(rq.x), -1.2)), -sdir), 0.0, 1.0);
      col = th * (ambCol + sunCol * day * roofLit) * mix(1.0, 0.75, rain * 0.5);
    }
    // window: glass by day, hearth by night — and its light POOLS on the ground
    let wc = hc + vec2f(0.038 * s, 0.03 * s);
    if (vg_box(q, wc, vec2f(0.016, 0.017) * s) < 0.0) {
      col = mix(sky * 0.6 + vec3f(0.05), vec3f(1.25, 0.85, 0.35), warmW);
      if (abs(q.x - wc.x) < 0.002 || abs(q.y - wc.y) < 0.002) { col = vec3f(0.15, 0.12, 0.09); }
    }
    let pool = q - (wc + vec2f(0.0, 0.075 * s));
    col += vec3f(1.0, 0.65, 0.25) * exp(-dot(pool * vec2f(1.0, 2.4), pool * vec2f(1.0, 2.4)) * 260.0 / s) * warmW * night * 0.55;
  }
  // the well: stone ring, little roof, rope
  {
    let wc = vec2f(0.32, 0.30);
    let wd2 = length(q - wc);
    if (wd2 < 0.045) {
      var stone = mix(vec3f(0.30, 0.30, 0.33), vec3f(0.45, 0.44, 0.46), fbm((q - wc) * 60.0, 2));
      stone *= 0.6 + 0.4 * clamp(dot(normalize(q - wc), -sdir), 0.0, 1.0);
      col = stone * (ambCol + sunCol * day);
      if (wd2 < 0.026) { col = mix(vec3f(0.03, 0.05, 0.09), sky * 0.5, 0.4); }  // water sees the sky
    }
    if (abs(q.x - wc.x) < 0.052 && abs(q.y - (wc.y - 0.075)) < 0.010) {
      col = vec3f(0.3, 0.2, 0.11) * (ambCol + sunCol * day * 0.9);
    }
    if (abs(q.x - wc.x + 0.002) < 0.0015 && q.y > wc.y - 0.07 && q.y < wc.y - 0.02) { col = vec3f(0.5, 0.45, 0.35) * (0.4 + 0.6 * day); }
  }
  // market stall
  {
    let mc = vec2f(0.58, 0.12);
    if (vg_box(q, mc + vec2f(0.0, 0.035), vec2f(0.055, 0.028)) < 0.0) {
      col = vec3f(0.3, 0.22, 0.13) * (ambCol + sunCol * day * 0.8);
    }
    if (vg_box(q, mc - vec2f(0.0, 0.012), vec2f(0.068, 0.02)) < 0.0) {
      let stripe = step(0.5, fract(q.x * 42.0));
      col = mix(vec3f(0.62, 0.14, 0.10), vec3f(0.78, 0.72, 0.60), stripe) * (ambCol * 1.2 + sunCol * day);
    }
  }

  // ── the villagers, lit and shadowed ──
  let day6 = 0.35 + 0.65 * day;
  for (var i = 0; i < 8; i++) {
    let vx = uni(10 + i * 4);
    let vy = uni(11 + i * 4);
    let act = uni(12 + i * 4);
    let dir = uni(13 + i * 4);
    let fi = f32(i);
    if (abs(act - 2.0) < 0.25) {
      let zt = fract(t * 0.3 + fi * 0.4);
      let zp = q - vec2f(vx + 0.02 + zt * 0.03, vy - 0.10 - zt * 0.06);
      if (abs(zp.x) < 0.008 && abs(zp.y) < 0.008 && hash21(vec2f(fi, floor(t * 0.3))) > 0.4) {
        col += vec3f(0.6, 0.6, 0.8) * (1.0 - zt) * 0.4 * night;
      }
      continue;
    }
    var shirt = vec3f(0.55, 0.40, 0.22);
    if (i % 4 == 1) { shirt = vec3f(0.26, 0.40, 0.48); }
    if (i % 4 == 2) { shirt = vec3f(0.46, 0.26, 0.34); }
    if (i % 4 == 3) { shirt = vec3f(0.32, 0.44, 0.26); }
    let walking = abs(act - 1.0) < 0.25;
    let working = abs(act - 3.0) < 0.25;
    let bob = select(0.0, abs(sin(t * 8.0 + fi * 2.0)) * 0.006, walking);
    let feet = vec2f(vx, vy - bob);
    // their own cast shadow, stretched by the hour
    let srel = q - feet;
    let salong = dot(srel, sdir);
    let sacross = srel.x * sdir.y - srel.y * sdir.x;
    if (salong > 0.0 && salong < shLen * 0.05 && abs(sacross) < 0.010 * (1.0 - salong / (shLen * 0.055))) {
      col *= 1.0 - 0.45 * day;
    }
    // body: lit toward the sun
    if (vg_box(q, feet - vec2f(0.0, 0.026), vec2f(0.011, 0.02)) < 0.0) {
      let faceLit = 0.55 + 0.45 * sunSide * sign(q.x - feet.x);
      col = shirt * (ambCol + sunCol * day * (0.3 + 0.8 * faceLit));
    }
    if (length(q - (feet - vec2f(0.0, 0.056))) < 0.011) {
      col = vec3f(0.85, 0.62, 0.45) * (ambCol + sunCol * day * (0.4 + 0.5 * (0.5 + 0.5 * sunSide * sign(q.x - feet.x))));
    }
    if (working) {
      let sw = sin(t * 5.0 + fi) * 0.6;
      let tip = feet + vec2f(dir * (0.022 + 0.012 * sw), -0.02 - 0.012 * abs(sw));
      if (vg_seg(q, feet - vec2f(0.0, 0.03), tip) < 0.004) { col = vec3f(0.66, 0.60, 0.46) * day6; }
    }
  }
  // the dog, sunlit + shadow speck
  {
    let dg = vec2f(uni(5), uni(6));
    let wag = sin(t * 10.0) * 0.008;
    if (vg_seg(q, dg + sdir * 0.012, dg + sdir * 0.03) < 0.008) { col *= 1.0 - 0.35 * day; }
    if (vg_box(q, dg, vec2f(0.014, 0.008)) < 0.0) { col = vec3f(0.42, 0.30, 0.18) * (ambCol + sunCol * day); }
    if (length(q - (dg - vec2f(0.016, 0.006))) < 0.008) { col = vec3f(0.48, 0.34, 0.20) * (ambCol + sunCol * day); }
    if (length(q - (dg + vec2f(0.018, -0.004 + wag))) < 0.004) { col = vec3f(0.48, 0.34, 0.20) * (ambCol + sunCol * day); }
  }
  // rain: streaks catch the light
  if (rain > 0.02) {
    let rp = vec2f(q.x * 30.0 + q.y * 6.0, q.y * 18.0 - t * 26.0);
    if (hash21(floor(rp)) > 0.8 && fract(rp.y) < 0.55) { col += (ambCol * 0.8 + vec3f(0.1)) * rain * 0.9; }
  }
  // fireflies + tavern spill
  col += vec3f(1.0, 0.62, 0.22) * exp(-dot(q - vec2f(0.62, 0.52), q - vec2f(0.62, 0.52)) * 26.0) * night * 0.35;
  if (night > 0.6 && q.y > 0.3 && q.x < 0.0) {
    let fp = q * 12.0 + vec2f(sin(t * 0.3), 0.0);
    if (hash21(floor(fp)) > 0.965) {
      let bl = pow(0.5 + 0.5 * sin(t * 2.0 + hash21(floor(fp)) * 50.0), 4.0);
      col += vec3f(0.9, 1.2, 0.3) * smoothstep(0.2, 0.04, length(fract(fp) - 0.5)) * bl * 0.8;
    }
  }
  // gentle grade: lifted blacks at night, warm bloom lives in the tube
  col = col / (1.0 + col * 0.25);
  return col;
}

fn visual_tv_set(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let p = (uv + vec2f(1.0)) * 256.0;
  let t = time;

  // the room: dark, lit by the set
  var col = vec3f(0.012, 0.011, 0.015) * (1.0 + 0.35 * fbm3(p * 0.01));

  let C = vec2f(256.0, 238.0);
  let half = vec2f(172.0, 122.0);
  let dBez = sdRoundedBox(p - C, half + vec2f(22.0, 26.0), 14.0);
  let dScr = sdRoundedBox(p - C, half, 10.0);

  // glow spill on the room
  let flick = 0.94 + 0.06 * sin(t * 47.0) * sin(t * 31.0);
  col += vec3f(0.10, 0.12, 0.16) * flick * exp(-max(dBez, 0.0) * 0.02);

  // bezel: warm plastic with a highlight
  if (dBez < 0.0 && dScr >= 0.0) {
    col = mix(vec3f(0.10, 0.085, 0.07), vec3f(0.16, 0.14, 0.12), fbm3(p * 0.15) * 0.5);
    col *= 0.8 + 0.4 * smoothstep(20.0, -30.0, p.y - (C.y - half.y));
    // channel knob
    let kd = length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)));
    if (kd < 7.0) {
      col = vec3f(0.05);
      let ka = 6.2831 * uni(0) / 6.0 - 1.57;
      if (length(p - (C + vec2f(half.x + 8.0, half.y + 14.0)) - vec2f(cos(ka), sin(ka)) * 4.0) < 1.6) { col = vec3f(0.7); }
    }
  }

  // the screen: barrel-distorted, phosphor, scanlines — a CRT calling a channel
  if (dScr < 0.0) {
    var q = (p - C) / half;                                   // -1..1
    q *= 1.0 + 0.10 * dot(q, q);                              // barrel
    if (abs(q.x) > 1.0 || abs(q.y) > 1.0) {
      col = vec3f(0.0);                                       // over-scan black
    } else {
      // ── THE CALL: channel word by number ──
      let ch = i32(uni(0) + 0.5);
      var scr: vec3f;
      if (ch == 0) { scr = ch_static(q, t); }
      else if (ch == 1) { scr = ch_plasma(q, t); }
      else if (ch == 2) { scr = ch_pong(q, t); }
      else if (ch == 3) { scr = ch_boids(q, t); }
      else if (ch == 4) { scr = ch_sitcom(q, t); }
      else { scr = ch_village(q, t); }

      // switch burst: static bleeds over the program
      if (uni(1) > 0.01) { scr = mix(scr, ch_static(q, t * 3.0), min(uni(1) * 1.4, 1.0)); }

      // CRT dress: phosphor triads, scanlines, corner falloff, flicker
      let px = i32(p.x * 3.0) % 3;
      var mask = vec3f(0.85);
      if (px == 0) { mask = vec3f(1.25, 0.72, 0.72); }
      else if (px == 1) { mask = vec3f(0.72, 1.25, 0.72); }
      else { mask = vec3f(0.72, 0.72, 1.25); }
      scr *= mask;
      scr *= 0.82 + 0.18 * sin(p.y * 3.14159);                // scanlines
      scr *= flick;
      scr *= 1.0 - 0.45 * pow(length(q), 4.0);                // corner falloff
      col = scr * 1.35;                                       // HDR — bloom catches the tube
    }
  }

  // set shadow on the floor
  col *= 1.0 - 0.3 * smoothstep(30.0, 0.0, abs(p.y - (C.y + half.y + 40.0))) * smoothstep(half.x + 40.0, half.x - 20.0, abs(p.x - C.x));

  return vec4f(col, 1.0);
}
